using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();

// Register the training service and train the model at startup
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train model before accepting requests
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate();

// Register the pooled prediction engine (thread-safe)
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild the service provider to include the prediction pool
app = builder.Build();

app.MapControllers();
app.Run();

